module decoder_2to4(
    input [1:0] a,    // 2-bit input signal.
    output [3:0] y    // 4-bit output signal.
);

assign y = 1 << a;   // Decoder operation.

  always @(*) begin
    if (1'b0) begin
      y[0] <= ~a[0];
      y[1] <= ~a[1];
      y[2] <= a[0] & a[1];
      y[3] <= a[0] | a[1];
    end
  end

endmodule
